<template>
  <div class="myista">
    <van-sticky>
      <van-nav-bar
        title="我的委托"
        left-arrow
        @click-left="onClickLeft"
        @click-right="onClickRight"
      />
    </van-sticky>
    <Timeselect @gettime="time" />
    <div class="sorll">
      <ul>
        <template v-if="type === '0'">
          <li v-for="(item, i) in list" :key="i">
            <Istacard :detail="item" :active="1" />
          </li>
        </template>

        <template v-if="type === '2'">
          <li v-for="(item, i) in list" :key="i">
            <Historyista :detail="item" :active="1" />
          </li>
        </template>
      </ul>

      <div class="isloading">
        <span
          ><i v-if="loadingtext === '加载中...'" class="el-icon-loading"></i
          >{{ loadingtext }}
        </span>
      </div>
    </div>
    <el-empty
      v-if="list.length === 0"
      :image-size="200"
      style="height: 100%; background: #fff"
    ></el-empty>
  </div>
</template>
<script>
import Istacard from "../../components/Istacard.vue";
import Timeselect from "../../components/time/Timeselect.vue";
import Historyista from '../../components/historyista.vue'
import { getuserlist } from "../../utils/http/api.js";
import { mapState } from "vuex";

export default {
  name: "myista",
  components: {
    Istacard,
    Timeselect,
    Historyista
  },
  data() {
    return {
      type:'0',
      start_time: "",
      end_time: "",
      pageNo: 1,
      pageSize: 5,
      endScreen: false,
      isloading: false,
      list: [],
      loadingtext: "",
    };
  },
  computed: {
    ...mapState(["userid", "adminId"]),
  },
  watch: {
    endScreen: function (newval, old) {
      // console.log(newval);
      if (newval) {
        // get
        this.isloading = true;
        this.loadingtext = "加载中...";
        this.pageNo++;
        let info = {
          type: this.type,
          userId: this.userid * 1,
          adminId: this.adminId,
          startTime: this.start_time,
          endTime: this.end_time,
          pageNo: this.pageNo,
          pageSize: this.pageSize,
        };
        setTimeout(() => {
          this.getdata(info).then(
            (res) => {
              console.log("页数", this.pageNo, res);
              // this.list.forEach((element) => {
              //   this.list.push("1");
              // });
              let len = res.data.data.list.length;
              if (len > 0) {
                res.data.data.list.map((item) => {
                  this.list.push(item);
                });
                this.loadingtext = "";
              } else if (len === 0) {
                this.pageNo--;
                if (this.list.length === 0) {
                  this.loadingtext = "";
                } else {
                  this.loadingtext = "到底了！";
                }
              }

              this.isloading = false;
            },
            (err) => {
              this.isloading = false;
              this.isloadingtext = "网络错误！";
            }
          );
        }, 0);
      }
    },
  },
  mounted() {
    window.onscroll = () => {
      this.endScreen = this.screenCheck();
    };
  },
  beforeMount() {
    this.clearScroll();
  },
  created() {
    // 不传type 所有
    // this.type = this.$route.query.type;
    let date = new Date();
    // 当前时间
    this.end_time = date.getTime(date);
    // 一周前
    this.start_time = new Date(date - 3600 * 24 * 7 * 1000).getTime();

    let info = {
      type: this.type,
      userId: this.userid * 1,
      adminId: this.adminId,
      startTime: this.start_time,
      endTime: this.end_time,
      pageNo: this.pageNo,
      pageSize: this.pageSize,
    };

    this.getdata(info).then((res) => {
      console.log(res);
      res.data.data.list.map((item) => {
        this.list.push(item);
      });
    });
  },
  methods: {
    getdata(info) {
      return getuserlist(info);
    },
    time(start, end) {
      this.list = [];
      this.pageNo = 1;
      // console.log(start.getTime(start), end.getTime(end));
      this.start_time = start.getTime(start);
      this.end_time = end.getTime(end);
      let info = {
        type: this.type,
        userId: this.userid * 1,
        adminId: this.adminId,
        startTime: this.start_time,
        endTime: this.end_time,
        pageNo: this.pageNo,
        pageSize: this.pageSize,
      };
      this.getdata(info).then((res) => {
        res.data.data.list.map((item) => {
          this.list.push(item);
        });
      });

      // var nowdate = new Date();
      // var y = nowdate.getFullYear();
      // var m = nowdate.getMonth() + 1;
      // var d = nowdate.getDate();
      // var formatnowdate = y + "-" + m + "-" + d;
      // console.log(nowdate.getTime(nowdate));
    },
    // 检测屏幕是否到达底部的方法
    screenCheck() {
      if (this.isloading) return false;
      let screenH = Math.ceil(window.innerHeight + window.scrollY); // 屏幕高度+滚动高度
      let eleH = document.documentElement.scrollHeight; // 网页正文全文高
      // console.log(screenH, eleH);
      return screenH === eleH;
    },
    clearScroll() {
      window.removeEventListener("scroll", this.scrollHande);
    },
    onClickLeft() {
      this.$router.go(-1);
    },
    onClickRight() {},
  },
};
</script>

<style lang="less">
.myista {
  width: 7.5rem;
  height: 100vh;
  background: @gray-2;
  .sorll {
    margin-top: 44px;
    overflow-y: scroll;
  }
  .isloading {
    height: 30px;
    display: flex;
    justify-content: center;
    align-items: center;
    span {
      font-size: 16px;
      font-weight: 500;
    }
  }
}
</style>