import {
  deepClone
} from './deppClone'
export function once(data) {
  // 存储处理过的检测信息
  let sampleList = []
  //  存储原始检测信息
  let list = deepClone(data.sampleList)

  delete data.sampleList;
  // 存储基本信息
  let entrustInfo = Object.assign({}, data);

  list.forEach((item, j) => {
    // console.log(item);
    sampleList.push({
      modelId: item.modelId,
      objectCount: item.objectCount.toString(),
      productCompanyName: item.productCompanyName,
      productId: item.productId,
      productname: item.productName,
      productNumber: item.productName.toString(),
      productStandardSource: item.productStandardSource,
      sampleType: item.sampleType === '单一' ? 1 : 2,
      checkList: []
    })
    for (let obj in item) {
      if (obj === 'checkList') {
        item.checkList.forEach((value, i) => {
          // console.log(value);

          sampleList[j].checkList.push({
            checkItemId: value.checkItemId,
            checkTimes: value.checkTimes,
            standardId: value.standardId
          })
        })
      }

    }
  })
  return {
    sampleList,
    entrustInfo
  }
}